             {
                 var filePath = Path.Combine(_env.WebRootPath ?? _env.ContentRootPath, course.TeachingMaterialImagePath.TrimStart('/').Replace('/', Path.DirectorySeparatorChar));
                 if (System.IO.File.Exists(filePath))
