        [TestMethod]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            // Arrange
            // First remove enrollments and course assignments referencing this course
            var enrollments = _context.Enrollments.Where(e => e.CourseID == 1050).ToList();
            _context.Enrollments.RemoveRange(enrollments);
            var cas = _context.CourseAssignments.Where(ca => ca.CourseID == 1050).ToList();
            _context.CourseAssignments.RemoveRange(cas);
            _context.SaveChanges();

            var initialCount = _context.Courses.Count();

            // Act
