using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    /// <summary>
    /// Shared test helpers for creating InMemory DbContext and seeding data.
    /// </summary>
    public static class TestHelpers
    {
        /// <summary>
        /// Creates a fresh InMemory SchoolContext with a unique database name.
        /// </summary>
        public static SchoolContext CreateInMemoryContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;

            var context = new SchoolContext(options);
            return context;
        }

        /// <summary>
        /// Seeds the context with standard test data (students, instructors, departments, courses, enrollments).
        /// </summary>
        public static void SeedTestData(SchoolContext context)
        {
            var students = new Student[]
            {
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2021-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2022-09-01") },
            };
            context.Students.AddRange(students);
            context.SaveChanges();

            var instructors = new Instructor[]
            {
                new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") },
                new Instructor { FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06") },
            };
            context.Instructors.AddRange(instructors);
            context.SaveChanges();

            var departments = new Department[]
            {
                new Department { Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[0].ID },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[1].ID },
            };
            context.Departments.AddRange(departments);
            context.SaveChanges();

            var courses = new Course[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = departments[0].DepartmentID },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = departments[1].DepartmentID },
                new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = departments[1].DepartmentID },
            };
            context.Courses.AddRange(courses);
            context.SaveChanges();

            var enrollments = new Enrollment[]
            {
                new Enrollment { StudentID = students[0].ID, CourseID = 1050, Grade = Grade.A },
                new Enrollment { StudentID = students[0].ID, CourseID = 4022, Grade = Grade.C },
                new Enrollment { StudentID = students[1].ID, CourseID = 1045, Grade = Grade.B },
            };
            context.Enrollments.AddRange(enrollments);
            context.SaveChanges();

            var courseAssignments = new CourseAssignment[]
            {
                new CourseAssignment { InstructorID = instructors[0].ID, CourseID = 1050 },
                new CourseAssignment { InstructorID = instructors[1].ID, CourseID = 1045 },
            };
            context.CourseAssignments.AddRange(courseAssignments);
            context.SaveChanges();
        }

        /// <summary>
        /// Drains the static NotificationService queue to prevent cross-test leakage.
        /// </summary>
        public static void DrainNotificationQueue()
        {
            using var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }
    }
}

