            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert
            _sut.Dispose();
            // Call again to test double-dispose safety
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_QueueCap_EnforcesMaxLength()
        {
            // Arrange - send more than 500 notifications
            for (int i = 0; i < 510; i++)
            {
                _sut.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            // Act - count remaining notifications
            int count = 0;
            while (_sut.ReceiveNotification() != null)
            {
                count++;
            }

            // Assert - should have at most 500 notifications
            Assert.IsTrue(count <= 500, $"Queue should cap at 500 but had {count}");
        }

        [TestMethod]
        public void SendNotification_MultipleOperations_AllEnqueued()
        {
            // Act
            _sut.SendNotification("Student", "1", "Stu", EntityOperation.CREATE);
            _sut.SendNotification("Student", "1", "Stu", EntityOperation.UPDATE);
            _sut.SendNotification("Student", "1", "Stu", EntityOperation.DELETE);

            // Assert
            var n1 = _sut.ReceiveNotification();
            var n2 = _sut.ReceiveNotification();
            var n3 = _sut.ReceiveNotification();
            var n4 = _sut.ReceiveNotification();

            Assert.IsNotNull(n1);
            Assert.AreEqual("CREATE", n1.Operation);
            Assert.IsNotNull(n2);
            Assert.AreEqual("UPDATE", n2.Operation);
            Assert.IsNotNull(n3);
            Assert.AreEqual("DELETE", n3.Operation);
            Assert.IsNull(n4);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndexCorrectly()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };

            // Act
            var list = new PaginatedList<int>(items, 10, 2, 3);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_CalculatesTotalPagesCorrectly()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };

            // Act  - 10 items, page size 3 => ceil(10/3) = 4
            var list = new PaginatedList<int>(items, 10, 1, 3);

            // Assert
            Assert.AreEqual(4, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_WhenCountDivisibleByPageSize_CalculatesCorrectTotalPages()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };

            // Act  - 9 items, page size 3 => 3
            var list = new PaginatedList<int>(items, 9, 1, 3);

            // Assert
            Assert.AreEqual(3, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_AddsItemsToList()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 10, 1, 5);

            // Assert
            Assert.AreEqual(3, list.Count);
            Assert.AreEqual("a", list[0]);
            Assert.AreEqual("b", list[1]);
            Assert.AreEqual("c", list[2]);
        }

        [TestMethod]
        public void HasPreviousPage_WhenOnFirstPage_ReturnsFalse()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            // Assert
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_WhenOnSecondPage_ReturnsTrue()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            // Assert
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_WhenOnLastPage_ReturnsFalse()
        {
            // Arrange  - 10 items, page 2, page size 5 => 2 total pages => on last page
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            // Assert
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_WhenNotOnLastPage_ReturnsTrue()
        {
            // Arrange  - 10 items, page 1, page size 5 => 2 total pages => not on last
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            // Assert
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_WhenOnlyOnePage_ReturnsFalse()
        {
            // Arrange  - 3 items, page 1, page size 5 => 1 total page
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);

            // Assert
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasPreviousPage_MiddlePage_ReturnsTrue()
        {
            // Arrange  - 30 items, page 2, page size 10 => 3 total pages
            var list = new PaginatedList<int>(new List<int>(), 30, 2, 10);

            // Assert
            Assert.IsTrue(list.HasPreviousPage);
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void Create_FromQueryable_ReturnsCorrectPage()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act - get page 2, page size 5
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(7, result[1]);
            Assert.AreEqual(8, result[2]);
            Assert.AreEqual(9, result[3]);
            Assert.AreEqual(10, result[4]);
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        public void Create_FirstPage_HasNoPrevoiusPage()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsTrue(result.HasNextPage);
        }

        [TestMethod]
        public void Create_LastPage_HasNoNextPage()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act - page 4 of 4 (page size 5)
            var result = PaginatedList<int>.Create(source, 4, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(16, result[0]);
            Assert.AreEqual(20, result[4]);
            Assert.IsTrue(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_LastPagePartial_HasCorrectCount()
        {
            // Arrange  - 13 items, page size 5 => 3 pages, last page has 3 items
            var source = Enumerable.Range(1, 13).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 5);

            // Assert
            Assert.AreEqual(3, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(13, result[2]);
            Assert.AreEqual(3, result.TotalPages);
        }

        [TestMethod]
        public void Create_SingleItem_ReturnsSinglePage()
        {
            // Arrange
            var source = new[] { 42 }.AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(42, result[0]);
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(1, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
        }
    }
}

