using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut = null!;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain the static queue to prevent cross-test leakage
            TestHelpers.DrainNotificationQueue();
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            TestHelpers.DrainNotificationQueue();
        }

        [TestMethod]
        public void SendNotification_FourParamOverload_EnqueuesNotification()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_FiveParamOverload_WithDisplayName_EnqueuesNotification()
        {
            // Act
            _sut.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE, "Teacher");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Course", notification.EntityType);
            Assert.AreEqual("1050", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Teacher", notification.CreatedBy);
            Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_CreateOperation_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.UPDATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student 'John Doe' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.DELETE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student 'John Doe' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            // Act
            _sut.SendNotification("Student", "42", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullDisplayName_UsesIdInMessage()
        {
            // Act
            _sut.SendNotification("Student", "42", null, EntityOperation.UPDATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
