        [TestMethod]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
        {
            // Act
            _sut.SendNotification("Student", "42", "   ", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            // Act
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(notification);
        }

        [TestMethod]
        public void ReceiveNotification_ReturnsNotificationsInFifoOrder()
        {
            // Arrange
            _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);

            // Act
            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            // Assert
            Assert.IsNotNull(first);
            Assert.AreEqual("Student", first.EntityType);
            Assert.AreEqual("1", first.EntityId);

            Assert.IsNotNull(second);
            Assert.AreEqual("Course", second.EntityType);
            Assert.AreEqual("2", second.EntityId);
        }

        [TestMethod]
        public void ReceiveNotification_DequeuedItemIsRemovedFromQueue()
        {
            // Arrange
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Act
            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            // Assert
            Assert.IsNotNull(first);
            Assert.IsNull(second);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToApproximatelyNow()
        {
            // Arrange
            var before = DateTime.Now.AddSeconds(-1);

            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var after = DateTime.Now.AddSeconds(1);
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before, $"CreatedAt {notification.CreatedAt} should be >= {before}");
            Assert.IsTrue(notification.CreatedAt <= after, $"CreatedAt {notification.CreatedAt} should be <= {after}");
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - MarkAsRead is a no-op but should not throw
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert
            _sut.Dispose();
            // Call again to test double-dispose safety
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_QueueCap_EnforcesMaxLength()
        {
            // Arrange - send more than 500 notifications
            for (int i = 0; i < 510; i++)
            {
                _sut.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            // Act - count remaining notifications
            int count = 0;
            while (_sut.ReceiveNotification() != null)
            {
                count++;
            }

            // Assert - should have at most 500 notifications
            Assert.IsTrue(count <= 500, $"Queue should cap at 500 but had {count}");
        }

        [TestMethod]
        public void SendNotification_MultipleOperations_AllEnqueued()
        {
            // Act
            _sut.SendNotification("Student", "1", "Stu", EntityOperation.CREATE);
            _sut.SendNotification("Student", "1", "Stu", EntityOperation.UPDATE);
            _sut.SendNotification("Student", "1", "Stu", EntityOperation.DELETE);

            // Assert
            var n1 = _sut.ReceiveNotification();
            var n2 = _sut.ReceiveNotification();
            var n3 = _sut.ReceiveNotification();
            var n4 = _sut.ReceiveNotification();

            Assert.IsNotNull(n1);
            Assert.AreEqual("CREATE", n1.Operation);
            Assert.IsNotNull(n2);
            Assert.AreEqual("UPDATE", n2.Operation);
            Assert.IsNotNull(n3);
            Assert.AreEqual("DELETE", n3.Operation);
            Assert.IsNull(n4);
        }
    }
}

