using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        private SchoolContext _context = null!;
        private NotificationsController _controller = null!;

        [TestInitialize]
        public void Setup()
        {
            TestHelpers.DrainNotificationQueue();
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new NotificationsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
            TestHelpers.DrainNotificationQueue();
        }

        [TestMethod]
        public void GetNotifications_WhenQueueEmpty_ReturnsSuccessWithEmptyList()
        {
            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);

            // Use reflection to inspect anonymous type
            var value = result.Value;
            var successProp = value!.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");
            Assert.IsNotNull(successProp);
            Assert.IsNotNull(countProp);
            Assert.AreEqual(true, successProp.GetValue(value));
            Assert.AreEqual(0, countProp.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_WithQueuedNotifications_ReturnsNotifications()
        {
            // Arrange
            _controller.notificationService.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            _controller.notificationService.SendNotification("Course", "2", "Test2", EntityOperation.UPDATE);

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value!.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");
            Assert.AreEqual(true, successProp!.GetValue(value));
            Assert.AreEqual(2, countProp!.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10Notifications()
        {
            // Arrange - add 15 notifications
            for (int i = 0; i < 15; i++)
            {
                _controller.notificationService.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            // Act
            var result = _controller.GetNotifications();

            // Assert
            var value = result.Value;
            var countProp = value!.GetType().GetProperty("count");
            Assert.AreEqual(10, countProp!.GetValue(value));
        }

        [TestMethod]
        public void GetNotifications_DrainsQueueUpTo10()
        {
            // Arrange - add 3 notifications
            for (int i = 0; i < 3; i++)
            {
                _controller.notificationService.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
            }

            // Act
            var result = _controller.GetNotifications();

            // Assert
            var value = result.Value;
            var countProp = value!.GetType().GetProperty("count");
            Assert.AreEqual(3, countProp!.GetValue(value));

            // Queue should be empty now (for those 3)
            var result2 = _controller.GetNotifications();
            var value2 = result2.Value;
            var countProp2 = value2!.GetType().GetProperty("count");
            Assert.AreEqual(0, countProp2!.GetValue(value2));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            // Act
            var result = _controller.MarkAsRead(1);

            // Assert
            Assert.IsNotNull(result);
            var value = result.Value;
            var successProp = value!.GetType().GetProperty("success");
            Assert.AreEqual(true, successProp!.GetValue(value));
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            // Act
            var result = _controller.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }
    }
}

